import{_ as B,C as A,o as n,c as g,a5 as e,b as l,w as a,a as o,E,a4 as i}from"./chunks/framework.sOZL8giL.js";const f=JSON.parse('{"title":"何时用多Agent","description":"","frontmatter":{},"headers":[],"relativePath":"04-多Agent架构/01-何时用多Agent.md","filePath":"04-多Agent架构/01-何时用多Agent.md","lastUpdated":null}'),s={name:"04-多Agent架构/01-何时用多Agent.md"};function h(p,t,C,b,_,c){const r=A("Mermaid"),d=A("DecisionTree");return n(),g("div",null,[t[2]||(t[2]=e('<h1 id="何时用多agent" tabindex="-1">何时用多Agent <a class="header-anchor" href="#何时用多agent" aria-label="Permalink to &quot;何时用多Agent&quot;">​</a></h1><blockquote><p>本章是 <strong>Hermes Engineering 系列</strong>第 4 模块的第 1 章。</p></blockquote><p>到底该不该用多Agent？什么时候用？怎么拆？两种工程哲学的较量——Anthropic 注重广度与解耦，Cognition 关注深度与一致性。</p><hr><h2 id="两种工程哲学" tabindex="-1">两种工程哲学 <a class="header-anchor" href="#两种工程哲学" aria-label="Permalink to &quot;两种工程哲学&quot;">​</a></h2><p>几乎在同一时间，Anthropic 发表了《How We Built Our Multi-Agent Research System》，Cognition AI（Devin 开发者）发表了《Don&#39;t Build Multi-Agents》。这不是简单的观点冲突，而是两种工程哲学的较量。</p><h3 id="cognition-的核心关切-可靠性" tabindex="-1">Cognition 的核心关切：可靠性 <a class="header-anchor" href="#cognition-的核心关切-可靠性" aria-label="Permalink to &quot;Cognition 的核心关切：可靠性&quot;">​</a></h3><p>在构建长程智能体时首要挑战是可靠性——对误差累积的控制。在多步骤推理系统中，如果每一步准确率不能维持极高水平，随着步骤增加系统整体成功率会呈指数级下降。</p><p>工程重点需要从提示词工程转向上下文工程——在动态系统中通过代码自动管理信息的流入流出，精准为模型提供当前决策所需的全部背景信息，同时屏蔽干扰信息。</p><h3 id="flappy-bird-案例" tabindex="-1">Flappy Bird 案例 <a class="header-anchor" href="#flappy-bird-案例" aria-label="Permalink to &quot;Flappy Bird 案例&quot;">​</a></h3>',10)),(n(),l(i,null,{default:a(()=>[E(r,{id:"mermaid-30",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20subgraph%20%E5%B9%B6%E8%A1%8C%E6%9E%B6%E6%9E%84%0A%20%20%20%20%20%20%20%20A%5BAgent%20A%3Cbr%2F%3E%E6%9E%84%E5%BB%BA%E7%BB%BF%E8%89%B2%E7%AE%A1%E9%81%93%E8%83%8C%E6%99%AF%5D%20--%3E%20C%5B8-bit%E5%83%8F%E7%B4%A0%E9%A3%8E%E6%A0%BC%5D%0A%20%20%20%20%20%20%20%20B%5BAgent%20B%3Cbr%2F%3E%E6%9E%84%E5%BB%BA%E6%B8%B8%E6%88%8F%E8%A7%92%E8%89%B2%E9%B8%9F%5D%20--%3E%20D%5B%E9%AB%98%E6%B8%85%E5%86%99%E5%AE%9E%E9%A3%8E%E6%A0%BC%5D%0A%20%20%20%20end%0A%20%20%20%20C%20--%3E%20E%5B%E9%9B%86%E6%88%90%5D%0A%20%20%20%20D%20--%3E%20E%0A%20%20%20%20E%20--%3E%20F%5B%E2%9D%8C%20%E9%A3%8E%E6%A0%BC%E4%B8%8D%E7%BB%9F%E4%B8%80%3Cbr%2F%3E%E9%80%BB%E8%BE%91%E4%B8%8D%E5%85%BC%E5%AE%B9%5D%0A%20%20%20%20style%20F%20fill%3A%23f66%0A"})]),fallback:a(()=>[...t[0]||(t[0]=[o(" Loading... ",-1)])]),_:1})),t[3]||(t[3]=e('<blockquote><p>💡 <strong>图解：</strong> 行动承载着隐性决策——并行架构把这些决策打散到不同上下文中，集成时必然撞车。</p></blockquote><p>典型的多 Agent 并行架构：Agent A 构建包含绿色管道的游戏背景，Agent B 构建游戏角色（一只鸟）。Agent A 基于训练数据倾向生成 8-bit 像素风格，Agent B 无法知晓这个决策，可能生成高清写实风格的鸟。集成时风格不统一、底层逻辑不兼容。</p><p>关键规律：<strong>行动承载着隐性决策。</strong> 在并行架构中这些隐性决策分散且难以察觉，必然导致一致性缺失。</p><h3 id="cognition-的结论" tabindex="-1">Cognition 的结论 <a class="header-anchor" href="#cognition-的结论" aria-label="Permalink to &quot;Cognition 的结论&quot;">​</a></h3><p>编程的核心是写操作，涉及大量细微的隐性决策。并行架构导致决策分散、上下文割裂，最终引发灾难性的一致性缺失。因此在现阶段应坚持使用单智能体。</p><hr><h2 id="anthropic-的回应-何时用多agent" tabindex="-1">Anthropic 的回应：何时用多Agent <a class="header-anchor" href="#anthropic-的回应-何时用多agent" aria-label="Permalink to &quot;Anthropic 的回应：何时用多Agent&quot;">​</a></h2><p>但 Anthropic 并非主张所有场景都用多 Agent。他们认为多 Agent 系统在需要广度而非深度的探索性任务中表现卓越。</p><h3 id="三类适合多-agent-的场景" tabindex="-1">三类适合多 Agent 的场景 <a class="header-anchor" href="#三类适合多-agent-的场景" aria-label="Permalink to &quot;三类适合多 Agent 的场景&quot;">​</a></h3><p><strong>1. 多角度研究</strong>：一个 Agent 擅长一个领域，另一个 Agent 擅长另一个领域，各自独立探索后汇总。</p><p><strong>2. 验证型子 Agent</strong>：最安全的拆分起点。主 Agent 负责写，子 Agent 负责验证——检查代码质量、安全漏洞、测试覆盖。验证型子 Agent 只读不写，不会产生冲突。</p><p><strong>3. 以上下文为中心的边界划分</strong>：当不同任务需要截然不同的上下文时（比如一个需要产品文档，一个需要代码库），用独立 Agent 避免上下文污染。</p><h3 id="第一刀切在哪" tabindex="-1">第一刀切在哪 <a class="header-anchor" href="#第一刀切在哪" aria-label="Permalink to &quot;第一刀切在哪&quot;">​</a></h3><p>最安全的第一刀是验证型子 Agent——只读不写，不存在隐性决策冲突。OpenAI 的 Arbor 安全 Agent 就是这个模式：自动审核代码、发现漏洞，因为它和 Codex 共享同一个高可读性仓库，能准确理解业务逻辑找出潜在风险。</p><h3 id="边界划分原则" tabindex="-1">边界划分原则 <a class="header-anchor" href="#边界划分原则" aria-label="Permalink to &quot;边界划分原则&quot;">​</a></h3><p>以任务的读写特性为第一刀：读操作（搜索、分析、验证）适合并行，写操作（编码、修改、创建）应该串行。以上下文需求为第二刀：需要不同上下文的子任务用独立 Agent 避免干扰。以依赖关系为第三刀：有前后依赖的子任务必须串行。</p><hr><h2 id="广度-vs-深度" tabindex="-1">广度 vs 深度 <a class="header-anchor" href="#广度-vs-深度" aria-label="Permalink to &quot;广度 vs 深度&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>多Agent（广度）</th><th>单Agent（深度）</th></tr></thead><tbody><tr><td>适合场景</td><td>探索性研究、多角度分析</td><td>编程、写操作密集任务</td></tr><tr><td>优势</td><td>覆盖面广、可并行</td><td>决策一致、无冲突</td></tr><tr><td>风险</td><td>隐性决策分散、一致性缺失</td><td>上下文窗口限制</td></tr><tr><td>解决方案</td><td>以读写分界、验证型拆分</td><td>串行接力、Clean State</td></tr></tbody></table><p>核心洞察：不是多 Agent 好不好，而是<strong>什么时候用</strong>。选择架构时先问：这个任务更需要广度还是深度？</p>',20)),(n(),l(i,null,{default:a(()=>[E(r,{id:"mermaid-147",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20A%5B%E9%9C%80%E8%A6%81%E5%A4%9AAgent%EF%BC%9F%5D%20--%3E%20B%7B%E4%BB%BB%E5%8A%A1%E9%9C%80%E8%A6%81%E5%B9%BF%E5%BA%A6%E8%BF%98%E6%98%AF%E6%B7%B1%E5%BA%A6%EF%BC%9F%7D%0A%20%20%20%20B%20--%3E%7C%E5%B9%BF%E5%BA%A6%3A%20%E5%A4%9A%E8%A7%92%E5%BA%A6%E7%A0%94%E7%A9%B6%7C%20C%5B%E9%80%82%E5%90%88%E5%A4%9AAgent%5D%0A%20%20%20%20B%20--%3E%7C%E6%B7%B1%E5%BA%A6%3A%20%E7%BC%96%E7%A0%81%E5%86%99%E6%93%8D%E4%BD%9C%7C%20D%5B%E9%80%82%E5%90%88%E5%8D%95Agent%5D%0A%20%20%20%20C%20--%3E%20E%7B%E7%AC%AC%E4%B8%80%E5%88%80%3A%20%E8%AF%BB%E5%86%99%E5%88%86%E7%95%8C%7D%0A%20%20%20%20E%20--%3E%7C%E8%AF%BB%E6%93%8D%E4%BD%9C%7C%20F%5B%E2%9C%85%20%E9%80%82%E5%90%88%E5%B9%B6%E8%A1%8C%3Cbr%2F%3E%E9%AA%8C%E8%AF%81%E5%9E%8B%E5%AD%90Agent%E6%9C%80%E5%AE%89%E5%85%A8%5D%0A%20%20%20%20E%20--%3E%7C%E5%86%99%E6%93%8D%E4%BD%9C%7C%20G%5B%E2%9D%8C%20%E5%BA%94%E8%AF%A5%E4%B8%B2%E8%A1%8C%3Cbr%2F%3E%E9%81%BF%E5%85%8D%E9%9A%90%E6%80%A7%E5%86%B3%E7%AD%96%E5%86%B2%E7%AA%81%5D%0A%20%20%20%20D%20--%3E%20H%5B%E4%B8%B2%E8%A1%8C%E6%8E%A5%E5%8A%9B%3Cbr%2F%3EClean%20State%5D%0A%20%20%20%20F%20--%3E%20I%5B%E4%BB%A5%E4%B8%8A%E4%B8%8B%E6%96%87%E9%9C%80%E6%B1%82%3Cbr%2F%3E%E4%B8%BA%E7%AC%AC%E4%BA%8C%E5%88%80%5D%0A%20%20%20%20I%20--%3E%20J%5B%E4%BB%A5%E4%BE%9D%E8%B5%96%E5%85%B3%E7%B3%BB%3Cbr%2F%3E%E4%B8%BA%E7%AC%AC%E4%B8%89%E5%88%80%5D%0A"})]),fallback:a(()=>[...t[1]||(t[1]=[o(" Loading... ",-1)])]),_:1})),t[4]||(t[4]=e('<blockquote><p>💡 <strong>图解：</strong> 选架构的第一刀永远是&quot;读还是写&quot;——读操作天生适合并行，写操作必须串行以防决策打架。</p></blockquote><hr><hr><h2 id="⚠️-常见错误" tabindex="-1">⚠️ 常见错误 <a class="header-anchor" href="#⚠️-常见错误" aria-label="Permalink to &quot;⚠️ 常见错误&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">❌ 错误做法</th><th style="text-align:left;">✅ 正确做法</th><th style="text-align:left;">为什么</th></tr></thead><tbody><tr><td style="text-align:left;">一上来就用多 Agent</td><td style="text-align:left;">先用单 Agent + 好的 Harness，解决不了再拆</td><td style="text-align:left;">多 Agent 增加协调成本和调试复杂度</td></tr><tr><td style="text-align:left;">按「角色」拆分（前端 + 后端 Agent）</td><td style="text-align:left;">按「上下文」拆分（不同领域知识独立窗口）</td><td style="text-align:left;">按角色拆分会增加跨角色通信开销</td></tr><tr><td style="text-align:left;">每个子任务都用最强模型</td><td style="text-align:left;">简单任务用小模型，复杂任务用大模型</td><td style="text-align:left;">成本和延迟不划算</td></tr><tr><td style="text-align:left;">子 Agent 共享完整上下文</td><td style="text-align:left;">隔离子 Agent 的上下文，只传递必要信息</td><td style="text-align:left;">共享上下文导致信息干扰</td></tr></tbody></table><hr><h2 id="🎮-交互式决策树" tabindex="-1">🎮 交互式决策树 <a class="header-anchor" href="#🎮-交互式决策树" aria-label="Permalink to &quot;🎮 交互式决策树&quot;">​</a></h2><p>不确定该不该用多 Agent？点下面的按钮一步步判断：</p>',8)),E(d),t[5]||(t[5]=e('<hr><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to &quot;本章要点&quot;">​</a></h2><ul><li>两种哲学：Cognition（深度一致性）vs Anthropic（广度解耦）</li><li>并行架构的核心风险：行动承载隐性决策，分散导致不一致</li><li>三类适合多 Agent 的场景：多角度研究、验证型子 Agent、上下文隔离</li><li>最安全的第一刀：验证型子 Agent（只读不写）</li><li>边界划分原则：读写分界 → 上下文需求 → 依赖关系</li></ul><hr><p><strong>下一章</strong>: <a href="./02-指挥官与工人.html">指挥官与工人</a></p><hr><p><a href="/">← 返回首页</a> | <a href="/03-Agent基础/">← 上一模块: Agent基础</a> | <a href="/05-Skill工程/">下一模块: Skill工程 →</a></p>',7))])}const D=B(s,[["render",h]]);export{f as __pageData,D as default};
